import React from "react";
import { Route } from "react-router-dom";
import { PublicRoute } from "../guards/RouteGuards";
import { PATHS } from "../constants/paths";
import LoginPage from "../pages/Auth/LoginPage";
import RegisterPage from "../pages/Auth/RegisterPage";
import ForgotPasswordPage from "../pages/Auth/ForgotPasswordPage";
import ResetPasswordPage from "../pages/Auth/ResetPasswordPage";

const authRoutes = (
  <>
    <Route path={PATHS.register} element={<PublicRoute element={<RegisterPage />} />} />
    <Route path={PATHS.login} element={<PublicRoute element={<LoginPage />} />} />
    <Route
      path={PATHS.forgotPassword}
      element={<PublicRoute element={<ForgotPasswordPage />} />}
    />
    <Route
      path={PATHS.resetPassword}
      element={<PublicRoute element={<ResetPasswordPage />} />}
    />
  </>
);

export default authRoutes;
